const express = require('express');
const crypto = require('crypto');
const app = express();

app.use(express.json());

// In-memory user database (in production use proper database)
const users = new Map();
const transactions = [];

class MobileMoneyService {
    constructor() {
        this.fee_percentage = 0.005; // 0.5% transaction fee
    }

    generateAccountNumber() {
        return 'MM' + crypto.randomBytes(4).toString('hex').toUpperCase();
    }

    createUser(phoneNumber, name) {
        const accountNumber = this.generateAccountNumber();
        users.set(phoneNumber, {
            accountNumber,
            name,
            balance: 0,
            transactions: []
        });
        return accountNumber;
    }

    deposit(phoneNumber, amount, agentId) {
        if (!users.has(phoneNumber)) {
            throw new Error('User not found');
        }

        const user = users.get(phoneNumber);
        user.balance += amount;

        const transaction = {
            id: crypto.randomUUID(),
            type: 'deposit',
            phoneNumber,
            amount,
            agentId,
            timestamp: new Date(),
            balance_after: user.balance
        };

        user.transactions.push(transaction);
        transactions.push(transaction);

        return transaction;
    }

    transfer(senderPhone, receiverPhone, amount) {
        if (!users.has(senderPhone) || !users.has(receiverPhone)) {
            throw new Error('User not found');
        }

        const sender = users.get(senderPhone);
        const receiver = users.get(receiverPhone);

        const fee = Math.ceil(amount * this.fee_percentage);
        const totalDeduct = amount + fee;

        if (sender.balance < totalDeduct) {
            throw new Error('Insufficient balance');
        }

        sender.balance -= totalDeduct;
        receiver.balance += amount;

        const transaction = {
            id: crypto.randomUUID(),
            type: 'transfer',
            sender: senderPhone,
            receiver: receiverPhone,
            amount,
            fee,
            timestamp: new Date(),
            sender_balance_after: sender.balance,
            receiver_balance_after: receiver.balance
        };

        sender.transactions.push({...transaction, counterparty: receiverPhone});
        receiver.transactions.push({...transaction, counterparty: senderPhone});
        transactions.push(transaction);

        return transaction;
    }

    getBalance(phoneNumber) {
        if (!users.has(phoneNumber)) {
            throw new Error('User not found');
        }
        return users.get(phoneNumber).balance;
    }

    getTransactionHistory(phoneNumber, limit = 10) {
        if (!users.has(phoneNumber)) {
            throw new Error('User not found');
        }
        return users.get(phoneNumber).transactions.slice(-limit);
    }
}

const mmService = new MobileMoneyService();

// API Routes
app.post('/users', (req, res) => {
    try {
        const { phoneNumber, name } = req.body;
        const accountNumber = mmService.createUser(phoneNumber, name);
        res.json({ accountNumber, message: 'User created successfully' });
    } catch (error) {
        res.status(400).json({ error: error.message });
    }
});

app.post('/deposit', (req, res) => {
    try {
        const { phoneNumber, amount, agentId } = req.body;
        const transaction = mmService.deposit(phoneNumber, amount, agentId);
        res.json(transaction);
    } catch (error) {
        res.status(400).json({ error: error.message });
    }
});

app.post('/transfer', (req, res) => {
    try {
        const { senderPhone, receiverPhone, amount } = req.body;
        const transaction = mmService.transfer(senderPhone, receiverPhone, amount);
        res.json(transaction);
    } catch (error) {
        res.status(400).json({ error: error.message });
    }
});

app.get('/balance/:phoneNumber', (req, res) => {
    try {
        const balance = mmService.getBalance(req.params.phoneNumber);
        res.json({ balance });
    } catch (error) {
        res.status(400).json({ error: error.message });
    }
});

app.get('/transactions/:phoneNumber', (req, res) => {
    try {
        const limit = parseInt(req.query.limit) || 10;
        const transactions = mmService.getTransactionHistory(req.params.phoneNumber, limit);
        res.json({ transactions });
    } catch (error) {
        res.status(400).json({ error: error.message });
    }
});

app.listen(3000, () => {
    console.log('Mobile Money API running on port 3000');
});

