// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/Pausable.sol";

/**
 * @title RecurringPaymentContract
 * @dev Smart contract for managing recurring payments on Ethereum
 */
contract RecurringPaymentContract is ReentrancyGuard, Ownable, Pausable {

    struct Subscription {
        address subscriber;
        address merchant;
        uint256 amount;
        uint256 frequency; // in seconds
        uint256 nextPayment;
        uint256 totalPaid;
        bool active;
        string description;
    }

    mapping(bytes32 => Subscription) public subscriptions;
    mapping(address => bytes32[]) public subscriberSubscriptions;
    mapping(address => bytes32[]) public merchantSubscriptions;

    uint256 public totalSubscriptions;
    uint256 public platformFee; // in basis points (e.g., 100 = 1%)

    event SubscriptionCreated(bytes32 indexed subscriptionId, address indexed subscriber, address indexed merchant);
    event PaymentExecuted(bytes32 indexed subscriptionId, uint256 amount, uint256 timestamp);
    event SubscriptionCancelled(bytes32 indexed subscriptionId);
    event FundsWithdrawn(address indexed merchant, uint256 amount);

    constructor(uint256 _platformFee) {
        platformFee = _platformFee;
    }

    /**
     * @dev Create a new subscription
     */
    function createSubscription(
        address _merchant,
        uint256 _amount,
        uint256 _frequency,
        string memory _description
    ) external whenNotPaused returns (bytes32) {

        require(_merchant != address(0), "Invalid merchant address");
        require(_amount > 0, "Amount must be greater than 0");
        require(_frequency >= 1 days, "Frequency must be at least 1 day");

        bytes32 subscriptionId = keccak256(
            abi.encodePacked(
                msg.sender,
                _merchant,
                _amount,
                block.timestamp
            )
        );

        require(subscriptions[subscriptionId].subscriber == address(0), "Subscription already exists");

        subscriptions[subscriptionId] = Subscription({
            subscriber: msg.sender,
            merchant: _merchant,
            amount: _amount,
            frequency: _frequency,
            nextPayment: block.timestamp + _frequency,
            totalPaid: 0,
            active: true,
            description: _description
        });

        subscriberSubscriptions[msg.sender].push(subscriptionId);
        merchantSubscriptions[_merchant].push(subscriptionId);
        totalSubscriptions++;

        emit SubscriptionCreated(subscriptionId, msg.sender, _merchant);
        return subscriptionId;
    }

    /**
     * @dev Execute payment for a subscription (can be called by anyone)
     */
    function executePayment(bytes32 _subscriptionId) external nonReentrant whenNotPaused {
        Subscription storage subscription = subscriptions[_subscriptionId];

        require(subscription.active, "Subscription is not active");
        require(subscription.subscriber != address(0), "Subscription does not exist");
        require(block.timestamp >= subscription.nextPayment, "Payment not due yet");

        uint256 feeAmount = (subscription.amount * platformFee) / 10000;
        uint256 merchantAmount = subscription.amount - feeAmount;

        // Check subscriber has sufficient balance
        require(address(this).balance >= subscription.amount, "Insufficient contract balance");

        // Update subscription
        subscription.nextPayment = block.timestamp + subscription.frequency;
        subscription.totalPaid += subscription.amount;

        // Transfer funds
        payable(subscription.merchant).transfer(merchantAmount);
        payable(owner()).transfer(feeAmount);

        emit PaymentExecuted(_subscriptionId, subscription.amount, block.timestamp);
    }

    /**
     * @dev Cancel a subscription
     */
    function cancelSubscription(bytes32 _subscriptionId) external {
        Subscription storage subscription = subscriptions[_subscriptionId];

        require(
            msg.sender == subscription.subscriber || msg.sender == subscription.merchant || msg.sender == owner(),
            "Not authorized to cancel"
        );

        subscription.active = false;
        emit SubscriptionCancelled(_subscriptionId);
    }

    /**
     * @dev Get subscription details
     */
    function getSubscription(bytes32 _subscriptionId) external view returns (
        address subscriber,
        address merchant,
        uint256 amount,
        uint256 frequency,
        uint256 nextPayment,
        uint256 totalPaid,
        bool active,
        string memory description
    ) {
        Subscription memory subscription = subscriptions[_subscriptionId];
        return (
            subscription.subscriber,
            subscription.merchant,
            subscription.amount,
            subscription.frequency,
            subscription.nextPayment,
            subscription.totalPaid,
            subscription.active,
            subscription.description
        );
    }

    /**
     * @dev Get subscriber's subscriptions
     */
    function getSubscriberSubscriptions(address _subscriber) external view returns (bytes32[] memory) {
        return subscriberSubscriptions[_subscriber];
    }

    /**
     * @dev Get merchant's subscriptions
     */
    function getMerchantSubscriptions(address _merchant) external view returns (bytes32[] memory) {
        return merchantSubscriptions[_merchant];
    }

    /**
     * @dev Withdraw funds (for merchants)
     * Note: In this simplified version, funds are transferred directly on payment execution
     */
    function withdrawFunds() external {
        // This would be implemented differently in a real system
        revert("Funds are transferred automatically on payment execution");
    }

    /**
     * @dev Update platform fee (only owner)
     */
    function updatePlatformFee(uint256 _newFee) external onlyOwner {
        require(_newFee <= 500, "Fee cannot exceed 5%");
        platformFee = _newFee;
    }

    /**
     * @dev Pause contract (emergency stop)
     */
    function pause() external onlyOwner {
        _pause();
    }

    /**
     * @dev Unpause contract
     */
    function unpause() external onlyOwner {
        _unpause();
    }

    /**
     * @dev Receive ETH deposits for subscriptions
     */
    receive() external payable {}
}
